	static inline ptr xrtDictGetWithKey(xdict objHT, Dict_Key* objKey)
	{
		Dict_Key* pNode = xrtAVLTreeSearch(&objHT->AVLT, objKey);
		if ( pNode ) {
			return &pNode[1];
		}
		return NULL;
	}
